mapper.insert:
/* mapper.log.com.erns.coching.ApiLogDAO.insert */
SELECT coching.create_monthly_partition('t_api_log_h', 'coching', now()::TIMESTAMP);
INSERT INTO coching.t_api_log_h ( RGT_DTTM , SITE_TYPE , MEMB_SEQ , LOG_TYPE , ROUTER_NM , ACCESS_IP , PROC_STATUS , API_URI , API_PARAMS , API_RES ) VALUES( now()::TIMESTAMP , COALESCE(#{siteType ,jdbcType=VARCHAR}, 'PARTNER_WEB') , COALESCE(#{membSeq ,jdbcType=INTEGER}, 0) , COALESCE(#{logType ,jdbcType=VARCHAR}, '000_000000') , #{routerNm ,jdbcType=VARCHAR} , #{accessIp ,jdbcType=VARCHAR} , #{procStatus ,jdbcType=CHAR} , #{apiUri ,jdbcType=VARCHAR} ,
CAST(#{apiParams} AS jsonb)
NULL
,
CAST(#{apiRes} AS jsonb)
NULL
)
